        let data = chunk
        chunk.removeAll(keepingCapacity: true)
        return data
    }

    func finish() -> Data? {
        lock.lock()
        defer { lock.unlock() }
        if closed {
            return nil
        }
        closed = true
        if chunk.isEmpty {
            return nil
        }
        let data = chunk
        chunk.removeAll(keepingCapacity: true)
        return data
    }

    func cancel() {
        lock.lock()
        closed = true
        chunk.removeAll(keepingCapacity: false)
        lock.unlock()
